import{_ as e,o,c as r,ae as t}from"./chunks/framework.BD9pLfSD.js";const n="/screenshots/booker-show-planning-stipulation-error.png",i="/screenshots/booker-show-planning-proposed-card.png",s="/screenshots/booker-show-planning-must-book-warning.png",h="/screenshots/booker-show-detail-qr-code-share.png",d="/screenshots/booker-dashboard-news-ticker.png",l="/screenshots/booker-show-planning.png",c="/screenshots/booker-match-narration.png",p="/screenshots/booker-show-history.png",_=JSON.parse('{"title":"Booker","description":"","frontmatter":{},"headers":[],"relativePath":"guide/booker.md","filePath":"guide/booker.md"}'),g={name:"guide/booker.md"};function u(m,a,w,b,k,f){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="booker" tabindex="-1">Booker <a class="header-anchor" href="#booker" aria-label="Permalink to &quot;Booker&quot;">​</a></h1><p>Welcome to the Booker guide. This documentation is automatically generated from the latest game features.</p><h2 id="show-planning-—-stipulation-required-error" tabindex="-1">Show Planning — Stipulation Required Error <a class="header-anchor" href="#show-planning-—-stipulation-required-error" aria-label="Permalink to &quot;Show Planning — Stipulation Required Error&quot;">​</a></h2><p>When a rivalry with heat ≥ 30 is on the card but has no match rule (stipulation), approval is blocked. The error dialog lists each affected rivalry. Edit the segment and add a rule such as Steel Cage or Last Man Standing before approving.</p><p><img src="'+n+'" alt="Show Planning — Stipulation Required Error"></p><hr><h2 id="show-planning-—-proposed-card" tabindex="-1">Show Planning — Proposed Card <a class="header-anchor" href="#show-planning-—-proposed-card" aria-label="Permalink to &quot;Show Planning — Proposed Card&quot;">​</a></h2><p>After the AI proposes segments, the booker reviews the card before approving. Rivalries with heat ≥ 10 that are not on the card will trigger an advisory when the Approve button is clicked.</p><p><img src="'+i+'" alt="Show Planning — Proposed Card"></p><hr><h2 id="show-planning-—-unbooked-rivalries-warning" tabindex="-1">Show Planning — Unbooked Rivalries Warning <a class="header-anchor" href="#show-planning-—-unbooked-rivalries-warning" aria-label="Permalink to &quot;Show Planning — Unbooked Rivalries Warning&quot;">​</a></h2><p>When rivalries with heat ≥ 10 are not on the proposed card, a confirmation dialog lists each unbooked feud. The booker can go back and add them, or acknowledge and approve anyway — unbooked rivalries carry over to future shows.</p><p><img src="'+s+'" alt="Show Planning — Unbooked Rivalries Warning"></p><hr><h2 id="qr-code-match-share" tabindex="-1">QR Code Match Share <a class="header-anchor" href="#qr-code-match-share" aria-label="Permalink to &quot;QR Code Match Share&quot;">​</a></h2><p>The QR share button on a match segment opens a dialog with a scannable QR code. The URL uses the machine&#39;s LAN IP address so phones on the same network can navigate directly to the match page.</p><p><img src="'+h+'" alt="QR Code Match Share"></p><hr><h2 id="dashboard-with-news-ticker" tabindex="-1">Dashboard with News Ticker <a class="header-anchor" href="#dashboard-with-news-ticker" aria-label="Permalink to &quot;Dashboard with News Ticker&quot;">​</a></h2><p>Latest headlines and rumors are visible directly on the booker dashboard.</p><p><img src="'+d+'" alt="Dashboard with News Ticker"></p><hr><h2 id="show-planning" tabindex="-1">Show Planning <a class="header-anchor" href="#show-planning" aria-label="Permalink to &quot;Show Planning&quot;">​</a></h2><p>The Show Planning interface allows you to book matches and segments for an upcoming show. Drag and drop wrestlers to create matches, set stipulations, and define segment types.</p><p><img src="'+l+'" alt="Show Planning"></p><hr><h2 id="match-narration" tabindex="-1">Match Narration <a class="header-anchor" href="#match-narration" aria-label="Permalink to &quot;Match Narration&quot;">​</a></h2><p>Bring your matches to life with AI-generated or manual narration. The Story Director uses match participants, rules, and outcomes to weave a compelling narrative of the action. The new structured transcript format separates objective action from character-driven commentary.</p><p><img src="'+c+'" alt="Match Narration"></p><hr><h2 id="show-history" tabindex="-1">Show History <a class="header-anchor" href="#show-history" aria-label="Permalink to &quot;Show History&quot;">​</a></h2><p>View a complete history of all booked shows. Click on any show to view its detailed results, ratings, and match history.</p><p><img src="'+p+'" alt="Show History"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="show-card-validation-walkthrough" tabindex="-1">Show Card Validation Walkthrough <a class="header-anchor" href="#show-card-validation-walkthrough" aria-label="Permalink to &quot;Show Card Validation Walkthrough&quot;">​</a></h3><p>After the booker confirms, the segments are saved to the show. Each approved segment enters the adjudication pipeline — the match engine resolves outcomes, updates wrestler stats, and the AI generates narration ready for broadcast.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/booker-show-planning-card-validation-walkthrough.mp4" type="video/mp4"></video><hr>',39)])])}const P=e(g,[["render",u]]);export{_ as __pageData,P as default};
